// Evaluate service health and detect state changes
// Uses static data to track previous state and avoid repeat alerts

const ollamaResult = $('Check Ollama').first();
const n8nResult = $('Check n8n').first();
const webUiResult = $('Check Open WebUI').first();

// Determine up/down for each service
const ollamaUp = !ollamaResult.json.error && (ollamaResult.json.models !== undefined || ollamaResult.json.statusCode !== undefined);
const n8nUp = !n8nResult.json.error && n8nResult.json.json?.status === 'ok';
const webUiUp = !webUiResult.json.error && (webUiResult.json.statusCode < 500 || webUiResult.json.statusCode === undefined);

// Use workflow static data to track state between runs
const workflowStaticData = $getWorkflowStaticData('global');
const prev = workflowStaticData.serviceStates || { ollama: true, n8n: true, webui: true };

const current = { ollama: ollamaUp, n8n: n8nUp, webui: webUiUp };

// Find state changes
const alerts = [];
const recoveries = [];

if (prev.ollama && !current.ollama) alerts.push('🔴 *Ollama* is DOWN — agents cannot respond');
if (!prev.ollama && current.ollama) recoveries.push('🟢 *Ollama* recovered');

if (prev.n8n && !current.n8n) alerts.push('🔴 *n8n* is DOWN — automation offline');
if (!prev.n8n && current.n8n) recoveries.push('🟢 *n8n* recovered');

if (prev.webui && !current.webui) alerts.push('🔴 *Open WebUI* is DOWN');
if (!prev.webui && current.webui) recoveries.push('🟢 *Open WebUI* recovered');

// Persist current state
workflowStaticData.serviceStates = current;

const messages = [...alerts, ...recoveries];
if (messages.length === 0) {
  return [{ json: { hasAlert: false } }];
}

const text = messages.join('\n');
const isAlert = alerts.length > 0;

return [{ json: { hasAlert: true, isAlert, text } }];
